import modal
from fastapi import FastAPI, Body

app = modal.App("fastapi-json-transform")
image = modal.Image.debian_slim().pip_install("fastapi")

web_app = FastAPI()

@web_app.get("/")
def read_root():
    return {"status": "ok", "service": "json-transform"}

@web_app.post("/transform")
def transform(data: list = Body(...), operation: str = Body(...)):
    if operation == "reverse":
        result = data[::-1]
    elif operation == "sort":
        result = sorted(data)
    else:
        result = data
    return {"result": result}

@app.function(image=image)
@modal.asgi_app()
def fastapi_app():
    return web_app

@app.local_entrypoint()
def main():
    import httpx

    url = fastapi_app.web_url
    print(f"Verifying endpoint at {url}")

    # Health check
    response = httpx.get(url)
    if response.status_code == 200 and response.json().get("status") == "ok":
        print("Health check passed!")

        # Store results in Modal Dict
        results_dict = modal.Dict.from_name("fastapi-json-transform-output", create_if_missing=True)
        results_dict["health_check"] = "ok"
        results_dict["endpoint_deployed"] = True
        print("Results stored in Modal Dict.")
    else:
        print(f"Health check failed: {response.status_code} {response.text}")

